// Represents (2 + 3) * 4
const expr: Expr = {
  type: "mul",
  left: {
    type: "add",
    left: { type: "num", value: 2 },
    right: { type: "num", value: 3 }
  },
  right: { type: "num", value: 4 }
};

console.log(evaluate(expr));

exercises.solution:
type NumLit = { type: "num"; value: number };
type Add = { type: "add"; left: Expr; right: Expr };
type Mul = { type: "mul"; left: Expr; right: Expr };
type Expr = NumLit | Add | Mul;

function evaluate(expr: Expr): number {
  switch (expr.type) {
    case "num":
      return expr.value;
    case "add":
      return evaluate(expr.left) + evaluate(expr.right);
    case "mul":
      return evaluate(expr.left) * evaluate(expr.right);
  }
}

const expr: Expr = {
  type: "mul",
  left: {
    type: "add",
    left: { type: "num", value: 2 },
    right: { type: "num", value: 3 }
  },
  right: { type: "num", value: 4 }
};

console.log(evaluate(expr));

